formulas.expression:
IF(
  /* L1 - Policy related */
  OR(
    /* Complaint or Other from anyone */
    OR(
      {!varReasonForRequest} = "I have a complaint",
      {!varReasonForRequest} = "Other"
    ),
    /* LA policy/guidance question */
    AND(
      {!varAreYou} = "Local authority user",
      {!varReasonForRequest} = "I have a question about the policy or guidance"
    )
  ),
  "L1 - Policy related",
  "L2 - Service queries"
)
